import React, { useState, useEffect, useCallback } from 'react';
import { TrendingUp, Loader, AlertCircle, DollarSign, ShoppingCart, Calendar } from 'lucide-react';
import api from '../../services/api';

const ADMIN_SALES_REPORT_FILTERS_KEY = 'khmart_admin_sales_reports_filters';

const getSaleDateValue = (sale) => sale?.saleDate ?? sale?.dateCreated ?? sale?.createdDate ?? null;
const getSaleAmount = (sale) => Number(sale?.totalAmount ?? sale?.amount ?? 0);

const readSavedFilters = () => {
  try {
    const raw = localStorage.getItem(ADMIN_SALES_REPORT_FILTERS_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') return null;
    return parsed;
  } catch {
    return null;
  }
};

const SalesReports = () => {
  const savedFilters = readSavedFilters();
  const [sales, setSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [timeRange, setTimeRange] = useState(savedFilters?.timeRange || 'month'); // 'week', 'month', 'year'
  const [selectedDate, setSelectedDate] = useState(savedFilters?.selectedDate || new Date().toISOString().split('T')[0]);

  const fetchSales = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const response = await api.get('/sales');
      const payload = response?.data;
      const data = Array.isArray(payload) ? payload : (payload?.items || []);
      setSales(data);
    } catch (err) {
      console.error('Error fetching sales:', err);
      setError('Failed to load sales data. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchSales();
  }, [fetchSales]);

  useEffect(() => {
    localStorage.setItem(
      ADMIN_SALES_REPORT_FILTERS_KEY,
      JSON.stringify({ timeRange, selectedDate }),
    );
  }, [timeRange, selectedDate]);

  // Calculate date range
  const getDateRange = () => {
    const end = new Date(selectedDate);
    const start = new Date(end);

    switch (timeRange) {
      case 'week':
        start.setDate(start.getDate() - 7);
        break;
      case 'month':
        start.setMonth(start.getMonth() - 1);
        break;
      case 'year':
        start.setFullYear(start.getFullYear() - 1);
        break;
      default:
        break;
    }

    return { start, end };
  };

  const { start: startDate, end: endDate } = getDateRange();

  // Filter sales by date range
  const filteredSales = sales.filter((sale) => {
    const saleDate = new Date(getSaleDateValue(sale) || 0);
    if (Number.isNaN(saleDate.getTime())) {
      return false;
    }
    return saleDate >= startDate && saleDate <= endDate;
  });

  // Calculate metrics
  const totalRevenue = filteredSales.reduce((sum, sale) => sum + getSaleAmount(sale), 0);
  const totalTransactions = filteredSales.length;
  const averageTransaction = totalTransactions > 0 ? totalRevenue / totalTransactions : 0;

  // Group sales by date
  const salesByDate = filteredSales.reduce((acc, sale) => {
    const date = new Date(getSaleDateValue(sale) || 0).toLocaleDateString();
    if (date === 'Invalid Date') {
      return acc;
    }
    if (!acc[date]) acc[date] = { date, count: 0, total: 0 };
    acc[date].count += 1;
    acc[date].total += getSaleAmount(sale);
    return acc;
  }, {});

  const dailySales = Object.values(salesByDate).sort((a, b) => new Date(a.date) - new Date(b.date));

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Sales Reports</h2>
        <button
          onClick={fetchSales}
          className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-medium"
        >
          Refresh
        </button>
      </div>

      {/* Filters */}
      <div className="flex gap-3 flex-wrap bg-white p-4 rounded-lg border border-gray-200">
        <div className="flex items-center gap-2">
          <Calendar className="w-5 h-5 text-gray-600" />
          <input
            type="date"
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div className="flex gap-2 ml-auto">
          {['week', 'month', 'year'].map((range) => (
            <button
              key={range}
              onClick={() => setTimeRange(range)}
              className={`px-4 py-2 rounded-lg font-medium transition-colors capitalize ${
                timeRange === range
                  ? 'bg-blue-500 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              Last {range}
            </button>
          ))}
        </div>
      </div>

      {/* Key Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="p-6 bg-white border border-gray-200 rounded-xl shadow-sm hover:shadow-md transition-shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Total Revenue</p>
              <p className="text-3xl font-bold text-gray-900 mt-2">
                ${totalRevenue.toFixed(2)}
              </p>
              <p className="text-xs text-gray-500 mt-1">
                {filteredSales.length} transactions
              </p>
            </div>
            <DollarSign className="w-12 h-12 text-green-400" />
          </div>
        </div>

        <div className="p-6 bg-white border border-gray-200 rounded-xl shadow-sm hover:shadow-md transition-shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Transactions</p>
              <p className="text-3xl font-bold text-gray-900 mt-2">{totalTransactions}</p>
              <p className="text-xs text-gray-500 mt-1">
                Avg: ${averageTransaction.toFixed(2)}
              </p>
            </div>
            <ShoppingCart className="w-12 h-12 text-blue-400" />
          </div>
        </div>

        <div className="p-6 bg-white border border-gray-200 rounded-xl shadow-sm hover:shadow-md transition-shadow">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Avg Per Transaction</p>
              <p className="text-3xl font-bold text-gray-900 mt-2">
                ${averageTransaction.toFixed(2)}
              </p>
              <p className="text-xs text-gray-500 mt-1">Based on total revenue</p>
            </div>
            <TrendingUp className="w-12 h-12 text-orange-400" />
          </div>
        </div>
      </div>

      {/* Content */}
      {loading ? (
        <div className="flex items-center justify-center py-12">
          <Loader className="w-8 h-8 text-blue-500 animate-spin" />
        </div>
      ) : error ? (
        <div className="p-4 border border-red-200 rounded-lg bg-red-50">
          <div className="flex items-center gap-3">
            <AlertCircle className="w-5 h-5 text-red-500" />
            <p className="text-sm text-red-700">{error}</p>
          </div>
        </div>
      ) : dailySales.length === 0 ? (
        <div className="text-center py-12 bg-gray-50 rounded-xl">
          <ShoppingCart className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <p className="text-gray-600 font-medium">No sales found</p>
          <p className="text-gray-500 text-sm">No sales data for the selected period</p>
        </div>
      ) : (
        <div className="space-y-4">
          <h3 className="text-lg font-semibold text-gray-900">Daily Sales Breakdown</h3>
          <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 border-b border-gray-200">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Date</th>
                    <th className="px-6 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Transactions</th>
                    <th className="px-6 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Total Revenue</th>
                    <th className="px-6 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Avg Per Sale</th>
                  </tr>
                </thead>
                <tbody>
                  {dailySales.map((day, idx) => (
                    <tr key={idx} className="border-b border-gray-100 hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 font-medium text-gray-900">{day.date}</td>
                      <td className="px-6 py-4 text-right text-gray-600">{day.count}</td>
                      <td className="px-6 py-4 text-right font-semibold text-green-600">
                        ${day.total.toFixed(2)}
                      </td>
                      <td className="px-6 py-4 text-right text-gray-600">
                        ${(day.total / day.count).toFixed(2)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SalesReports;
